// Cross-validation tests for NSGA-II multi-objective operations.
// Python reference values generated by tests/nsga_cross_validate_baseline.py.

use std::collections::HashMap;
use optuna_rs::multi_objective::{crowding_distance, fast_non_dominated_sort, dominates};
use optuna_rs::study::StudyDirection;
use optuna_rs::trial::{FrozenTrial, TrialState};

const TOL: f64 = 1e-10;

fn load_baseline() -> serde_json::Value {
    let data = include_str!("nsga_baseline_values.json");
    serde_json::from_str(data).expect("Failed to parse nsga baseline JSON")
}

fn get_f64(val: &serde_json::Value, key: &str) -> f64 {
    match &val[key] {
        serde_json::Value::Number(n) => n.as_f64().unwrap(),
        serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
        serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
        serde_json::Value::String(s) if s == "NaN" => f64::NAN,
        v => panic!("Unexpected value for {key}: {v:?}"),
    }
}

fn get_f64_vec(val: &serde_json::Value, key: &str) -> Vec<f64> {
    val[key]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| match v {
            serde_json::Value::Number(n) => n.as_f64().unwrap(),
            serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
            serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
            serde_json::Value::String(s) if s == "NaN" => f64::NAN,
            other => panic!("Unexpected value in {key}: {other:?}"),
        })
        .collect()
}

fn get_int_vec(val: &serde_json::Value, key: &str) -> Vec<i64> {
    val[key]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_i64().unwrap())
        .collect()
}

fn assert_close(got: f64, expected: f64, tol: f64, label: &str) {
    if expected.is_infinite() {
        assert!(
            got.is_infinite() && got.signum() == expected.signum(),
            "{label}: expected {expected}, got {got}"
        );
    } else if expected.is_nan() {
        assert!(got.is_nan(), "{label}: expected NaN, got {got}");
    } else {
        let diff = (got - expected).abs();
        let denom = expected.abs().max(1.0);
        assert!(
            diff / denom < tol,
            "{label}: expected {expected}, got {got}, rel_err = {:.2e}",
            diff / denom
        );
    }
}

fn make_trial(number: i64, values: Vec<f64>) -> FrozenTrial {
    FrozenTrial::new(
        number,
        TrialState::Complete,
        None,
        Some(values),
        Some(chrono::Utc::now()),
        Some(chrono::Utc::now()),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        number,
    )
    .unwrap()
}

// ═══════════════════════════════════════════════════════════════════════════
//  1. Crowding distance
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_crowding_distance_2d() {
    let b = load_baseline();
    let expected = get_f64_vec(&b, "cd_2d");

    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 5.0]),
        make_trial(1, vec![2.0, 3.0]),
        make_trial(2, vec![3.0, 2.0]),
        make_trial(3, vec![4.0, 1.0]),
        make_trial(4, vec![5.0, 0.0]),
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let cd = crowding_distance(&trial_refs, &dirs);

    for (i, (&got, &exp)) in cd.iter().zip(expected.iter()).enumerate() {
        assert_close(got, exp, TOL, &format!("cd_2d[{i}]"));
    }
}

