// ═══════════════════════════════════════════════════════════════════════════
//  2. Non-dominated sort
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_nds_2d() {
    let b = load_baseline();
    let expected = get_int_vec(&b, "nds_ranks_2d");

    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 4.0]),
        make_trial(1, vec![2.0, 2.0]),
        make_trial(2, vec![4.0, 1.0]),
        make_trial(3, vec![3.0, 3.0]),
        make_trial(4, vec![5.0, 5.0]),
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);

    // Convert fronts to per-trial ranks
    let mut ranks = vec![0i64; trials.len()];
    for (rank, front) in fronts.iter().enumerate() {
        for &idx in front {
            ranks[idx] = rank as i64;
        }
    }

    assert_eq!(ranks, expected, "nds_ranks_2d mismatch");
}

