// ═══════════════════════════════════════════════════════════════════════════
//  3. Dominates function
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_dominates_basic() {
    let dirs_min = vec![StudyDirection::Minimize, StudyDirection::Minimize];

    // [1, 2] dominates [2, 3]
    assert!(dominates(&[1.0, 2.0], &[2.0, 3.0], &dirs_min));
    // [2, 3] does NOT dominate [1, 2]
    assert!(!dominates(&[2.0, 3.0], &[1.0, 2.0], &dirs_min));
    // [1, 2] does NOT dominate [2, 1] (trade-off)
    assert!(!dominates(&[1.0, 2.0], &[2.0, 1.0], &dirs_min));
    // [1, 1] dominates [1, 2] (equal in first, better in second)
    assert!(dominates(&[1.0, 1.0], &[1.0, 2.0], &dirs_min));
    // [1, 1] does NOT dominate [1, 1] (identical)
    assert!(!dominates(&[1.0, 1.0], &[1.0, 1.0], &dirs_min));
}

#[test]
fn cv_dominates_maximize() {
    let dirs_max = vec![StudyDirection::Maximize, StudyDirection::Maximize];

    // [3, 3] dominates [2, 2] in maximize
    assert!(dominates(&[3.0, 3.0], &[2.0, 2.0], &dirs_max));
    // [2, 2] does NOT dominate [3, 3]
    assert!(!dominates(&[2.0, 2.0], &[3.0, 3.0], &dirs_max));
}
